// 초기화 파라미터 설정
var initializeParameter = new InitializeParameter()
{
    Type = ECommType.Socket,
    SocketIPAddress = "127.0.0.1",
    SocketPortNumber = 502
};

// 라이브러리 초기화
var device = new DeviceMeasurementKeyenceIL();
if (device.Initialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// 라이브러리 정리
device.DeInitialize();
return;

var device = new DeviceMeasurementKeyenceIL();
// DLL 버전 정보 읽기
string version = device.GetVersion(bReflesh: true);
Console.WriteLine($"DLL 버전: {version}");
return;

